### **Step 7: Create Notifications Settings Screen**

**Create `app/(tabs)/notifications.tsx`:**
```typescript
import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  Switch,
  TouchableOpacity,
  Alert,
  Platform,
} from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';
import { LinearGradient } from 'expo-linear-gradient';
import { colors } from '@/styles/commonStyles';
import { IconSymbol } from '@/components/IconSymbol';
import {
  subscribeToNotifications,
  getNotificationPermissionStatus,
} from '@/utils/onesignal';
import OneSignal from 'react-native-onesignal';

export default function NotificationsScreen() {
  const [notificationsEnabled, setNotificationsEnabled] = useState(false);
  const [permissionGranted, setPermissionGranted] = useState(false);

  useEffect(() => {
    checkPermissionStatus();
  }, []);

  const checkPermissionStatus = async () => {
    const hasPermission = await getNotificationPermissionStatus();
    setPermissionGranted(hasPermission);
    setNotificationsEnabled(hasPermission);
  };

  const handleToggle = async (value: boolean) => {
    if (!permissionGranted && value) {
      // Request permission first
      const granted = await OneSignal.Notifications.requestPermission(true);
      if (!granted) {
        Alert.alert(
          'Permission Required',
          'Please enable notifications in your device settings to receive updates.',
          [{ text: 'OK' }]
        );
        return;
      }
      setPermissionGranted(true);
    }

    subscribeToNotifications(value);
    setNotificationsEnabled(value);
  };

  return (
    <LinearGradient colors={[colors.primary, colors.secondary]} style={styles.container}>
      <SafeAreaView style={styles.safeArea}>
        <View style={styles.header}>
          <Text style={styles.title}>Notifications</Text>
        </View>

        <View style={styles.content}>
          <View style={styles.card}>
            <View style={styles.settingRow}>
              <View style={styles.settingInfo}>
                <IconSymbol name="bell.fill" size={24} color={colors.accent} />
                <View style={styles.settingText}>
                  <Text style={styles.settingTitle}>Push Notifications</Text>
                  <Text style={styles.settingDescription}>
                    Get notified when new articles are published
                  </Text>
                </View>
              </View>
              <Switch
                value={notificationsEnabled}
                onValueChange={handleToggle}
                trackColor={{ false: '#767577', true: colors.accent }}
                thumbColor={notificationsEnabled ? '#fff' : '#f4f3f4'}
              />
            </View>
          </View>

          <Text style={styles.infoText}>
            Enable notifications to stay updated with the latest news and articles from Yo Hit Radio.
          </Text>
        </View>
      </SafeAreaView>
    </LinearGradient>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  safeArea: { flex: 1 },
  header: {
    padding: 20,
