#### **3.1 Create Metadata Utility** (`utils/zenoMetadata.ts`)
```typescript
// Configuration
const ZENO_STATION_ID = 'hmc38shnrwzuv'; // From stream URL

export interface ZenoMetadata {
  title: string;
  artist: string;
  artworkUrl?: string;
}

export async function fetchZenoMetadata(): Promise<ZenoMetadata> {
  try {
    // Try Zeno API endpoint
    const url = `https://api.zeno.fm/stations/${ZENO_STATION_ID}/now-playing`;
    console.log('[Zeno Metadata] Fetching from:', url);

    const response = await fetch(url);
    const data = await response.json();

    console.log('[Zeno Metadata] Raw response:', JSON.stringify(data, null, 2));

    // Parse common Zeno field names
    const title = data?.title || data?.song || data?.track || data?.streamTitle || 'Yo Hit Radio';
    const artist = data?.artist || data?.now_playing?.artist || 'Live Stream';
    const artworkUrl = data?.artwork_url || data?.image || data?.cover;

    console.log('[Zeno Metadata] Parsed:', { title, artist, artworkUrl });

    return { title, artist, artworkUrl };
  } catch (error) {
    console.error('[Zeno Metadata] Fetch error:', error);
    return {
      title: 'Yo Hit Radio',
      artist: 'Live Stream',
    };
  }
}
```

#### **3.2 Update Home Screen with Metadata Polling**

**In `app/(tabs)/index.tsx`:**
```typescript
import { fetchZenoMetadata } from '@/utils/zenoMetadata';

// State
const [trackTitle, setTrackTitle] = useState('Yo Hit Radio');
const [artistName, setArtistName] = useState('Live Stream');
const [artworkUrl, setArtworkUrl] = useState<string | null>(null);

// Metadata polling with useCallback to fix lint
const startMetadataPolling = useCallback(() => {
  // Fetch immediately
  fetchZenoMetadata().then(metadata => {
    setTrackTitle(metadata.title);
    setArtistName(metadata.artist);
    setArtworkUrl(metadata.artworkUrl || null);
  });

  // Poll every 10 seconds
  const intervalId = setInterval(async () => {
    const metadata = await fetchZenoMetadata();
    setTrackTitle(metadata.title);
    setArtistName(metadata.artist);
    setArtworkUrl(metadata.artworkUrl || null);
  }, 10000);

  return intervalId;
}, []);

// Effect with proper dependencies
useEffect(() => {
  if (isPlaying) {
    const intervalId = startMetadataPolling();
    return () => clearInterval(intervalId);
  }
}, [isPlaying, startMetadataPolling]);

// UI binding
<Text style={styles.trackTitle}>{trackTitle}</Text>
<Text style={styles.artistName}>{artistName}</Text>
<Image 
  source={{ uri: artworkUrl || 'https://yohitradio.com/logo.png' }} 
  style={styles.artwork}
/>
```

